	i, j, count = map(int, input().split())
	self.swapAndHeapify(i, j, count)
	return '\n'.join(map(str, self.arr))


def swapAndHeapify(self, i, j, count):
	while i >= 0 and j < count:
		if j >= count - 1:
			i -= 1
			continue
		if i >= count - 1:
			j += 1
			continue
		if self.arr[i] > self.arr[j]:
			self.arr[i], self.arr[j] = self.arr[j], self.arr[i]
		i -= 1
		j += 1
		self.swapAndHeapify(i, j, count)
