using namespace std;

class Solution {
public:
bool swapAndHeapify(int arr[], int i, int j, int count) {
	while (i >= 0 && j < count) {
		if (j >= count - 1) {
			i -= 1;
			continue;
		}
		if (i >= count - 1) {
			j += 1;
			continue;
		}
		if (arr[i] > arr[j]) swap(arr[i], arr[j]);
		i -= 1;
		j += 1;
		swapAndHeapify(arr, i, j, count);
		return true;
	}
	return false;
}
};

